{"method_body":"{
  var boiling: real := 100.0 - (a as real) / 300.0;
  if t < 0.0 {
    s := "solid";
  } else if t == 0.0 {
    s := "solid or liquid";
  } else if 0.0 < t && t < boiling {
    s := "liquid";
  } else if t == boiling {
    s := "liquid or gaseous";
  } else {
    s := "gaseous";
  }
}"}

